window.HK2_LC7 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["She is giving a menu to a guest.", "She is setting a table for a meal.", "She is pouring water into a glass.", "She is flipping a light switch."], "optko": ["그녀는 손님에게 메뉴판을 주고 있다.", "그녀는 식사를 위해 테이블을 준비하고 있다.", "그녀는 유리잔에 물을 따르고 있다.", "그녀는 전등 스위치를 누르고 있다."], "ans": 1, "audio": "Test07_01.mp3", "img": "hk2_t7_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["Some people are removing their hats.", "Some people are filling up a basket.", "One of the people is moving a food stall.", "One of the people is kneeling on the sand."], "optko": ["몇몇 사람들이 모자를 벗고 있다.", "몇몇 사람들이 바구니를 가득 채우고 있다.", "사람들 중 한 명이 음식 가판대를 옮기고 있다.", "사람들 중 한 명이 모래에 무릎을 꿇고 있다."], "ans": 3, "audio": "Test07_02.mp3", "img": "hk2_t7_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["Some rope is hanging from a cliff.", "Some people are camping near a mountain.", "Climbing gear is being purchased.", "A man is resting his hand on a rock."], "optko": ["일부 밧줄이 절벽에 매달려 있다.", "몇몇 사람들이 산 근처에서 야영을 하고 있다.", "등산 장비가 구매되고 있다.", "한 남자가 자신의 손을 바위에 두고 있다."], "ans": 0, "audio": "Test07_03.mp3", "img": "hk2_t7_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["Reading materials have been placed on a rack.", "A man is holding a pair of scissors.", "One of the women is trimming a client's hair.", "One of the women is sitting under a dryer."], "optko": ["읽을거리들이 선반 위에 놓여 있다.", "한 남자가 가위를 들고 있다.", "여자들 중 한 명이 고객의 머리카락을 손질하고 있다.", "여자들 중 한 명이 건조기 아래에 앉아 있다."], "ans": 2, "audio": "Test07_04.mp3", "img": "hk2_t7_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["A road sign extends over multiple lanes.", "Vehicles have been left in a parking lot.", "A median divides a highway.", "Traffic cones have been lined up along the street."], "optko": ["도로 표지판이 여러 개의 차선들에 걸쳐 있다.", "차량들이 주차장에 놓여 있다.", "중앙 분리대가 고속도로를 가르고 있다.", "원뿔형의 교통 표지들이 도로를 따라 줄지어 있다."], "ans": 2, "audio": "Test07_05.mp3", "img": "hk2_t7_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["The man is carrying some hand tools.", "The man is digging a hole with a shovel.", "Farming equipment is being put away.", "There are structures at the edge of a field."], "optko": ["남자는 수공구들을 나르고 있다.", "남자는 삽으로 구멍을 파고 있다.", "농기구가 치워지고 있다.", "밭 가장자리에 구조물들이 있다."], "ans": 3, "audio": "Test07_06.mp3", "img": "hk2_t7_q6.jpg"}, {"n": 7, "part": 2, "q": "It isn't time for the training session yet, is it?", "qko": "아직 교육 시간이 아니에요, 그렇죠?", "opts": ["We have another half an hour.", "Ms. Rodriguez is leading it.", "I believe it's in the meeting room."], "optko": ["우리에게 아직 삼십 분이 남았어요.", "Ms. Rodriguez가 그것을 지도하고 있어요.", "그건 회의실에 있을 거라고 생각해요."], "ans": 0, "audio": "Test07_07.mp3"}, {"n": 8, "part": 2, "q": "Would you mind trading seats with me?", "qko": "저와 자리를 바꾸셔도 괜찮으신가요?", "opts": ["Sure, no problem at all.", "Oh, up near the stage.", "For a trading firm."], "optko": ["물론이죠, 전혀 문제없어요.", "아, 무대 가까이에요.", "무역 회사를 위해서요."], "ans": 0, "audio": "Test07_08.mp3"}, {"n": 9, "part": 2, "q": "What do you want me to bring you from the cafeteria?", "qko": "제가 구내식당에서 당신에게 무엇을 가져다주길 원하나요?", "opts": ["I enjoy working as a cook.", "Whatever you're eating.", "I brought it back yesterday."], "optko": ["저는 요리사로 일하는 것이 좋아요.", "당신이 먹는 것으로 아무거나요.", "제가 어제 그것을 다시 가져왔어요."], "ans": 1, "audio": "Test07_09.mp3"}, {"n": 10, "part": 2, "q": "Have you decided on a venue for the marketing convention?", "qko": "마케팅 컨벤션을 위한 장소를 정했나요?", "opts": ["The market is a major tourist attraction.", "Yes, but not very much.", "I can't find anything suitable."], "optko": ["그 시장은 주요 관광 명소예요.", "네, 하지만 많이는 아니에요.", "적합한 곳을 찾을 수가 없어요."], "ans": 2, "audio": "Test07_10.mp3"}, {"n": 11, "part": 2, "q": "Do you know when our rehearsal is supposed to begin?", "qko": "우리 리허설이 언제 시작하기로 되어 있는지 아시나요?", "opts": ["We'll start at noon.", "The lead actress is Julie Stone.", "It will be our rehearsal."], "optko": ["우리는 정오에 시작할 거예요.", "주연 여배우는 Julie Stone이에요.", "그것은 우리의 리허설이 될 거예요."], "ans": 0, "audio": "Test07_11.mp3"}, {"n": 12, "part": 2, "q": "Haven't you worked as a corporate lawyer?", "qko": "당신은 법인 고문 변호사로 일하신 적이 있지 않나요?", "opts": ["Where is the law office?", "Only for a few years.", "Let's visit the headquarters."], "optko": ["법률 사무소는 어디에 있나요?", "몇 년 동안만요.", "본사를 방문합시다."], "ans": 1, "audio": "Test07_12.mp3"}, {"n": 13, "part": 2, "q": "Who do I need to speak with about canceling my reservation?", "qko": "예약을 취소하는 것에 대해 제가 누구와 이야기해야 하나요?", "opts": ["The resort was just opened.", "You need to call our booking department.", "I have confirmed your stay."], "optko": ["리조트는 이제 막 개장했어요.", "저희 예약 담당 부서에 전화를 하셔야 합니다.", "제가 당신이 머무는 것을 확인했어요."], "ans": 1, "audio": "Test07_13.mp3"}, {"n": 14, "part": 2, "q": "Why is the videoconference equipment turned on?", "qko": "영상 회의 장비가 왜 켜져 있나요?", "opts": ["It was a very informative conference.", "For another couple of hours.", "The IT team is conducting a test on it."], "optko": ["매우 유익한 회의였어요.", "두 시간 더요.", "IT팀에서 그것을 시험해 보고 있어요."], "ans": 2, "audio": "Test07_14.mp3"}, {"n": 15, "part": 2, "q": "Where should I go to photocopy these forms?", "qko": "제가 이 양식들을 복사하기 위해서 어디로 가야 하나요?", "opts": ["The print shop down the block.", "They need 10 pages.", "No, sign on the dotted line."], "optko": ["블록 아래의 인쇄소요.", "그들은 10장이 필요해요.", "아니요, 점선 위에 서명을 해주세요."], "ans": 0, "audio": "Test07_15.mp3"}, {"n": 16, "part": 2, "q": "Which cities will Ms. Arden be visiting during her upcoming trip?", "qko": "Ms. Arden은 곧 있을 그녀의 여행 동안에 어느 도시들을 방문할 건가요?", "opts": ["At a recent meeting.", "Everyone had a lot of fun.", "I haven't seen her itinerary."], "optko": ["최근의 회의에서요.", "모든 사람들이 매우 즐거워했어요.", "저는 그녀의 여행 일정을 보지 못했어요."], "ans": 2, "audio": "Test07_16.mp3"}, {"n": 17, "part": 2, "q": "How did you learn to speak German so well?", "qko": "당신은 어떻게 독일어를 이렇게 잘하도록 배웠나요?", "opts": ["The speaker was very engaging.", "By taking classes in college.", "We didn't earn much."], "optko": ["그 발표자는 매우 매력적이었어요.", "대학에서 수업들을 들어서요.", "우리는 많이 벌지 못했어요."], "ans": 1, "audio": "Test07_17.mp3"}, {"n": 18, "part": 2, "q": "Where do you want to store these boxes of paper?", "qko": "당신은 이 종이가 든 상자들을 어디에 보관하고 싶나요?", "opts": ["For the office printers.", "I sent out for them.", "In the reception area for now."], "optko": ["사무실 프린터들을 위해서요.", "제가 그것들을 배달시켰어요.", "당분간은 응접실이에요."], "ans": 2, "audio": "Test07_18.mp3"}, {"n": 19, "part": 2, "q": "When should I print out the contract for you to review?", "qko": "당신이 검토할 수 있도록 언제 계약서를 출력해 드려야 하나요?", "opts": ["He will sign the contract.", "Anytime this afternoon.", "No problem, just pick it up."], "optko": ["그가 계약서에 서명할 거예요.", "오늘 오후 언제든지요.", "문제없어요, 그냥 가져가세요."], "ans": 1, "audio": "Test07_19.mp3"}, {"n": 20, "part": 2, "q": "These tables will have to be set for the banquet.", "qko": "이 테이블들은 연회를 위해 준비되어야 할 거예요.", "opts": ["Yes, I'm planning to come.", "Try adjusting the settings.", "How long will that task take?"], "optko": ["네, 저는 가려고 계획 중이에요.", "설정을 조정해 보세요.", "그 일은 얼마나 걸릴까요?"], "ans": 2, "audio": "Test07_20.mp3"}, {"n": 21, "part": 2, "q": "Aren't you conducting a safety inspection next week?", "qko": "당신은 다음 주에 안전 점검을 실시하지 않나요?", "opts": ["Yes, we got a good evaluation.", "He works as a conductor.", "I'll have to check my schedule."], "optko": ["네, 저희는 좋은 평가를 받았어요.", "그는 관리인으로 근무해요.", "제 일정을 확인해 봐야 할 거예요."], "ans": 2, "audio": "Test07_21.mp3"}, {"n": 22, "part": 2, "q": "Amy Tran is planning to travel overseas to consult clients, isn't she?", "qko": "Amy Tran은 고객들을 상담하기 위해 해외로 가려고 계획하고 있어요, 안 그런가요?", "opts": ["He's our most loyal client.", "That's right. She's going to Chile.", "The test results still haven't come."], "optko": ["그는 우리의 가장 충성스러운 고객이에요.", "맞아요. 그녀는 칠레로 갈 거예요.", "테스트 결과가 아직 나오지 않았어요."], "ans": 1, "audio": "Test07_22.mp3"}, {"n": 23, "part": 2, "q": "I can drop you off at the airport this weekend.", "qko": "저는 이번 주말에 당신을 공항에 내려줄 수 있어요.", "opts": ["Only if it's convenient for you.", "Yes, from my travel agent.", "The files are quite important."], "optko": ["당신에게 편리하다면요.", "네, 제 여행사 직원으로부터요.", "이 서류철들은 꽤 중요해요."], "ans": 0, "audio": "Test07_23.mp3"}, {"n": 24, "part": 2, "q": "We require receipts for all exchanges.", "qko": "저희는 모든 교환에 대해 영수증을 요구합니다.", "opts": ["To inquire about an event.", "You'll be pleased with this item.", "OK. I have mine with me."], "optko": ["행사에 관해 문의하기 위해서요.", "당신은 이 제품이 마음에 들 거예요.", "네. 저는 제 것을 갖고 있어요."], "ans": 2, "audio": "Test07_24.mp3"}, {"n": 25, "part": 2, "q": "Do you want help analyzing the data you collected?", "qko": "당신이 수집한 자료를 분석하는 데 도움을 원하나요?", "opts": ["No, Pete took care of that yesterday.", "Mr. Mack will distribute the programs.", "They're from the questionnaires."], "optko": ["아니요, Pete가 어제 그것을 처리했어요.", "Mr. Mack이 진행 순서표를 배부할 거예요.", "그것들은 설문지에서 나왔어요."], "ans": 0, "audio": "Test07_25.mp3"}, {"n": 26, "part": 2, "q": "Why did you decide to rename your company?", "qko": "당신은 왜 회사의 이름을 다시 짓기로 결정했나요?", "opts": ["Customers really like that product.", "The previous name seemed outdated.", "It sells custom jewelry."], "optko": ["고객들이 그 제품을 정말 좋아해요.", "이전의 이름이 구식인 것 같았어요.", "그곳은 주문 제작한 보석을 판매해요."], "ans": 1, "audio": "Test07_26.mp3"}, {"n": 27, "part": 2, "q": "Should I close the window, or do you want it open?", "qko": "제가 창문을 닫을까요, 아니면 당신은 그것을 열어두기를 원하나요?", "opts": ["Well, it is quite hot in here.", "I want to see it too.", "It's very close to my apartment."], "optko": ["음, 이 안이 상당히 덥네요.", "저도 그것을 보고 싶어요.", "그건 제 아파트에서 매우 가까워요."], "ans": 0, "audio": "Test07_27.mp3"}, {"n": 28, "part": 2, "q": "Could you put together a short presentation for the auto expo?", "qko": "자동차 전시회를 위한 짧은 발표를 준비해줄 수 있나요?", "opts": ["The car is fully automatic.", "Just put them in the showroom.", "I think so, but not until Monday."], "optko": ["그 자동차는 완전히 자동이에요.", "그냥 그것들을 전시실에 놓아주세요.", "그럴 수 있을 것 같은데, 월요일이나 되어야 해요."], "ans": 2, "audio": "Test07_28.mp3"}, {"n": 29, "part": 2, "q": "What did the realtor say about the condominium?", "qko": "부동산 중개인이 콘도에 대해 무엇을 말했나요?", "opts": ["A property management firm.", "No serious offers have been made on it.", "The one located in Woodrow Tower."], "optko": ["부동산 관리 회사요.", "그것에 대한 어떤 진지한 제안도 없었어요.", "Woodrow 타워에 위치한 거요."], "ans": 1, "audio": "Test07_29.mp3"}, {"n": 30, "part": 2, "q": "When is the office dress code going to go into effect?", "qko": "사무실 복장 규정은 언제 시행될 건가요?", "opts": ["Let's discuss that at the morning meeting.", "Salespeople must wear black shirts.", "Our business address has not changed."], "optko": ["그것에 관해 아침 회의에서 논의하도록 해요.", "판매원들은 검은색 셔츠를 입어야 해요.", "우리의 사무실 주소는 바뀌지 않았어요."], "ans": 0, "audio": "Test07_30.mp3"}, {"n": 31, "part": 2, "q": "The warehouse equipment has to be upgraded soon.", "qko": "창고 장비는 곧 개선돼야 해요.", "opts": ["They know where to go.", "The show should begin soon.", "But the forklift is only a year old."], "optko": ["그들은 어디로 가야 할지를 알아요.", "행사가 곧 시작될 거예요.", "하지만 그 지게차는 1년밖에 안 됐어요."], "ans": 2, "audio": "Test07_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test07_32-34.mp3", "qs": [{"n": 32, "q": "According to the woman, what needs to be changed?", "opts": ["An online database", "The details in a brochure", "A personnel policy", "The date of an event"], "ans": 1, "ko": "여자에 따르면, 무엇이 수정되어야 하는가?"}, {"n": 33, "q": "What has Sun Nam been tasked with?", "opts": ["Arranging a consultation", "Editing a report", "Leading a team", "Contacting an executive"], "ans": 2, "ko": "Sun Nam은 무슨 업무를 맡았는가?"}, {"n": 34, "q": "What does the woman say she will do later today?", "opts": ["Revise the format of a flyer", "Bring files to an administrator", "Leave for a trade fair", "Speak to a colleague"], "ans": 3, "ko": "여자는 오늘 늦게 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Good morning. Do you know who's responsible for editing our company's brochure for the upcoming trade fair? The manager wants to change some of the contact information in it, and he asked me to pass on his request to whoever is working on it.", "ko": "안녕하세요. 곧 있을 무역 박람회를 위해 우리 회사의 안내 책자를 편집하는 것을 누가 책임지는지 아시나요? 부장님께서 그 안에 있는 연락처 정보 일부를 수정하기를 원해서, 누구든 그 작업을 하고 있는 사람에게 그의 요청을 전달해달라고 제게 부탁했거든요."}, {"sp": "M", "en": "Sorry, I'm not sure. But you should talk to Sun Nam. She's overseeing the team that will be attending the fair, so she can provide you with that information.", "ko": "죄송하지만, 전 잘 모르겠어요. 하지만 Sun Nam에게 이야기하셔야 해요. 그녀가 박람회에 참석할 팀을 감독하고 있어서, 당신에게 그 정보를 줄 수 있어요."}, {"sp": "W", "en": "All right. I believe she will be out of the office until the early afternoon, but I'll speak with her once she returns. Thanks.", "ko": "알겠어요. 그녀가 이른 오후까지 사무실에 없을 것 같지만, 그녀가 돌아오면 그녀와 이야기할게요. 감사합니다."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test07_35-37.mp3", "qs": [{"n": 35, "q": "What did the man buy on Monday?", "opts": ["Dishware", "Beverages", "Furniture", "Appliances"], "ans": 0, "ko": "남자는 월요일에 무엇을 구매했는가?"}, {"n": 36, "q": "What problem does the man mention?", "opts": ["A warranty has expired.", "Some merchandise is too small.", "An item is damaged.", "A product was not shipped."], "ans": 2, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 37, "q": "What is the man told to do?", "opts": ["Return to a service desk", "Find a similar item", "Ask a supervisor for help", "Contact another branch"], "ans": 0, "ko": "남자는 무엇을 하도록 요청되는가?"}], "script": [{"sp": "M", "en": "Hello. I purchased this set of plates here on Monday. When I got home and took them out of the box, I noticed that one of them is broken.", "ko": "안녕하세요. 저는 월요일에 여기에서 이 접시 세트를 구입했어요. 제가 집에 가서 그것들을 상자에서 꺼냈을 때, 그것들 중 하나가 깨진 것을 알아챘어요."}, {"sp": "W", "en": "I can assist you with that. If you can provide proof of purchase, I would be happy to replace the set or give you a refund. Which would you prefer?", "ko": "그것에 대해 제가 고객님을 도와드릴 수 있습니다. 고객님께서 구입 증거를 제공하실 수 있으시다면, 제가 기꺼이 세트를 교환해드리거나 환불해드리겠습니다. 어떤 것이 좋으신가요?"}, {"sp": "M", "en": "I'd like to get another set. However, before you complete the transaction, can I grab some wine glasses that I want to purchase as well?", "ko": "저는 다른 세트가 갖고 싶어요. 하지만, 처리를 완료하기 전에, 제가 구입하고 싶은 와인 잔도 몇 개 가져와도 될까요?"}, {"sp": "W", "en": "Certainly. Just come back to the customer service desk once you're ready to check out.", "ko": "물론입니다. 그냥 고객님께서 계산할 준비가 되셨을 때 고객 서비스 창구로 돌아와 주세요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test07_38-40.mp3", "qs": [{"n": 38, "q": "What does the woman ask about?", "opts": ["When some dishes will be prepared", "Why some menu items are unavailable", "Where a group should be seated", "What an entrée is served with"], "ans": 0, "ko": "여자는 무엇에 관해 문의하는가?"}, {"n": 39, "q": "Why does the woman say, \"One of them just left\"?", "opts": ["To explain why a manager is upset", "To emphasize a problem's seriousness", "To criticize a coworker's decision", "To check if a restaurant will close"], "ans": 1, "ko": "여자는 \"그들 중 한 명은 방금 나갔어요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 40, "q": "What does the woman suggest?", "opts": ["Reducing a charge", "Bringing in more staff", "Canceling some orders", "Offering guests a free meal"], "ans": 0, "ko": "여자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "Dennis, how much longer will it be until the entrées for Table 5 are ready?", "ko": "Dennis, 5번 테이블을 위한 주요리가 준비되기까지 얼마나 더 걸릴까요?"}, {"sp": "M", "en": "At least 15 minutes. I'm . . . ah . . . I'm struggling to keep up with orders since we're short-staffed today.", "ko": "적어도 15분이요. 저는… 아… 오늘 직원이 부족해서 저는 주문을 따라가기 위해 애쓰고 있어요."}, {"sp": "W", "en": "I know it's not your fault, but the customers have been waiting for almost an hour . . . One of them just left.", "ko": "이것이 당신의 잘못이 아니라는 것을 알지만, 그 손님들이 거의 한 시간 동안 기다리고 있어요… 그들 중 한 명은 방금 나갔어요."}, {"sp": "M", "en": "Sorry, but I don't know what to tell you. I'm doing the best I can.", "ko": "죄송하지만, 뭐라고 말씀드려야 할지 모르겠네요. 저는 제가 할 수 있는 최선을 다하고 있어요."}, {"sp": "W", "en": "In that case, I think we'd better give them a discount to make up for the delay. I'll see if our manager is fine with that.", "ko": "그렇다면, 지연에 대해 보상하기 위해 그들에게 할인을 제공하는 것이 좋을 것 같아요. 제가 우리 매니저가 그것에 대해 괜찮다고 할지 확인할게요."}, {"sp": "M", "en": "OK. I'll inform you as soon as the food is ready.", "ko": "알겠어요. 음식이 준비되는 즉시 당신에게 알려줄게요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 미국식 발음 → 캐나다식 발음", "audio": "Test07_41-43.mp3", "qs": [{"n": 41, "q": "What is the conversation mainly about?", "opts": ["A partnership with an organization", "A way to raise money", "An event for volunteers", "A method for boosting morale"], "ans": 1, "ko": "대화는 주로 무엇에 관한 것인가?"}, {"n": 42, "q": "According to the man, what technique does the organization use?", "opts": ["Advertising on television", "Giving away gifts", "Charging membership fees", "Organizing special events"], "ans": 3, "ko": "남자에 따르면, 단체는 어떤 방법을 사용하는가?"}, {"n": 43, "q": "What does the man offer to do?", "opts": ["Develop a plan", "Announce a decision", "Assemble a team", "Contact a company"], "ans": 0, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W1", "en": "Wilma, I think our nonprofit organization needs a more effective fund-raising method.", "ko": "Wilma, 우리 비영리 단체에 더 효과적인 기금 모금 방법이 필요한 것 같아요."}, {"sp": "W2", "en": "Did you have something in mind?", "ko": "생각하신 것이 있나요?"}, {"sp": "W1", "en": "What about an online campaign?", "ko": "온라인 캠페인은 어때요?"}, {"sp": "W2", "en": "I'm not sure. Marcus, what do you think about changing to online fund-raising?", "ko": "전 잘 모르겠어요. Marcus, 온라인 기금 모금으로 변경하는 것에 대해 어떻게 생각하세요?"}, {"sp": "M", "en": "We could do that. Web-based campaigns cost very little, so it could save money. I'm sure it would be better than hosting fund-raising dinners like we do now.", "ko": "해볼 수 있을 것 같아요. 인터넷을 기반으로 하는 캠페인은 비용이 거의 들지 않아서, 돈을 절약할 수 있어요. 저는 그것이 우리가 지금 하는 것처럼 기금 모금 만찬을 주최하는 것보다 더 나을 것이라고 확신해요."}, {"sp": "W2", "en": "I see. Well . . . I'm open to the idea. However, I'm unfamiliar with the steps we'd need to take.", "ko": "그렇군요. 음… 저는 그 생각대로 할 용의가 있어요. 하지만 우리가 취해야 할 조치들을 잘 모르겠어요."}, {"sp": "M", "en": "I organized some campaigns at my previous job that were very successful. If you want, I can make an initial strategy proposal for you to review.", "ko": "이전 직장에서 매우 성공적이었던 몇몇 캠페인들을 제가 조직했어요. 원하시면, 당신이 검토할 수 있도록 제가 초기 전략 기획안을 만들 수 있어요."}, {"sp": "W1", "en": "Would you? That'd be helpful.", "ko": "그렇게 해주시겠어요? 그것이 도움이 될 거예요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test07_44-46.mp3", "qs": [{"n": 44, "q": "What concern does the woman mention?", "opts": ["She might need to leave early.", "She cannot afford to buy passes.", "She could not reach her relatives.", "She may have to miss an event."], "ans": 3, "ko": "여자는 무슨 걱정을 언급하는가?"}, {"n": 45, "q": "What does the man recommend?", "opts": ["Gathering more information", "Taking time to make a choice", "Coming with family members", "Getting some vouchers"], "ans": 2, "ko": "남자는 무엇을 제안하는가?"}, {"n": 46, "q": "What does the man say he did last year?", "opts": ["Volunteered his services", "Harvested produce", "Operated a booth", "Met up with acquaintances"], "ans": 1, "ko": "남자는 작년에 무엇을 했다고 말하는가?"}], "script": [{"sp": "W", "en": "Hello, this is Angela calling. I've got some bad news. I might not be able to join you at the Autumn Festival next Saturday. As it turns out, I have conflicting engagements.", "ko": "안녕하세요, Angela예요. 안 좋은 소식이 있어요. 다음 주 토요일에 있을 가을 축제에 당신과 함께하지 못할 수도 있어요. 알고 보니, 제가 겹치는 약속이 있어서요."}, {"sp": "M", "en": "I'm sorry to hear that. What do you have to do on Saturday?", "ko": "유감이네요. 토요일에 무엇을 해야 하나요?"}, {"sp": "W", "en": "I just found out that some of my relatives will be in town then. I have to entertain them during their visit.", "ko": "제 친척들 몇 명이 그때 이 지역에 있을 거라는 사실을 방금 알았어요. 저는 그들이 방문하는 동안 접대해야 해요."}, {"sp": "M", "en": "Well, you're welcome to bring them along. I'm sure they would enjoy the experience, as the festival has a lot of fun activities. Last year, I even harvested my own pumpkin to carve!", "ko": "음, 그들을 데리고 오셔도 돼요. 축제에 재미있는 활동들이 많기 때문에, 그들은 틀림없이 그 경험을 즐길 거예요. 작년에, 저는 조각할 저만의 호박을 수확하기도 했어요!"}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test07_47-49.mp3", "qs": [{"n": 47, "q": "What does the woman ask permission to do?", "opts": ["Take a personal day", "Attend a dental conference", "Extend a vacation", "Cancel an engagement"], "ans": 0, "ko": "여자는 무엇을 하려고 허락을 요청하는가?"}, {"n": 48, "q": "What will happen on Thursday?", "opts": ["New employees will be trained.", "A workshop will be conducted.", "A clinic will close for the holidays.", "Course materials will be made."], "ans": 1, "ko": "목요일에 무슨 일이 있을 것인가?"}, {"n": 49, "q": "What does the man suggest?", "opts": ["Asking a supervisor for time off", "Verifying an address", "Rescheduling an appointment", "Taking notes at a seminar"], "ans": 2, "ko": "남자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "Mr. Warner, I'm wondering if I could have the day off on Thursday. I need to go to the dentist for a checkup.", "ko": "Mr. Warner, 제가 목요일에 휴가를 낼 수 있는지 궁금해요. 검진을 위해 치과에 가야 하거든요."}, {"sp": "M", "en": "That's not a good day for you to be gone, as we're having a public relations workshop then. Everyone in our department is required to attend. You'd better possibly schedule your appointment for Friday or next Monday.", "ko": "그날이 당신이 가기에 좋은 날은 아닌 게, 그때 우리가 홍보 워크숍을 할 거라서요. 우리 부서의 모든 사람들이 참석해야 해요. 아마도 예약을 금요일이나 다음 주 월요일로 잡는 것이 좋을 거예요."}, {"sp": "W", "en": "That's right! I completely forgot. In that case, I can call the clinic and ask if they have an opening on Friday instead. I'm sure they will be able to accommodate my request.", "ko": "그러네요! 제가 완전히 잊어버렸어요. 그렇다면, 제가 병원에 전화해서 대신 금요일에 빈자리가 있는지를 물어볼 수 있어요. 그들이 제 요청을 수용할 수 있을 거라고 확신해요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test07_50-52.mp3", "qs": [{"n": 50, "q": "What did the man do last month?", "opts": ["Reviewed a document", "Signed a contract", "Contacted a publishing agent", "Drafted a manuscript"], "ans": 0, "ko": "남자는 지난달에 무엇을 했는가?"}, {"n": 51, "q": "Why is the woman excited?", "opts": ["She is going to give a public reading.", "She recently met a famous author.", "She was nominated for an award.", "She has been selected for publication."], "ans": 3, "ko": "여자는 왜 들떴는가?"}, {"n": 52, "q": "What does the man say about The Oxford Club?", "opts": ["It is closed this Tuesday afternoon.", "It is often busy during the week.", "It is situated near his workplace.", "It is one of his favorite cafés."], "ans": 2, "ko": "남자는 The Oxford Club에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Ms. Bont, this is Maurice Martin from Red Publishing.", "ko": "Ms. Bont, 저는 Red 출판사의 Maurice Martin입니다."}, {"sp": "W", "en": "Good morning, Mr. Martin. Are you calling about my manuscript?", "ko": "안녕하세요, Mr. Martin. 제 원고에 대해 전화하신 건가요?"}, {"sp": "M", "en": "Yes. I read over it last month, and it has a lot of potential. We received hundreds of submissions, but have chosen your book for publication.", "ko": "네. 제가 지난달에 그것을 꼼꼼히 읽어 봤는데, 많은 가능성을 지니고 있더군요. 저희는 수백 건의 제출물들을 받았지만, 귀하의 책을 출판하기로 결정했습니다."}, {"sp": "W", "en": "Oh, that's great to hear! I'm so honored!", "ko": "아, 반가운 얘기네요! 정말 영광이에요!"}, {"sp": "M", "en": "However, despite our interest, there are some problems that must be addressed. Nothing too major—mostly stylistic issues.", "ko": "하지만, 저희의 관심에도 불구하고, 반드시 다뤄져야 할 몇몇 문제들이 있어요. 아주 심각한 것은 아니고, 대부분 문체상의 문제들이죠."}, {"sp": "W", "en": "OK. Would you like to meet and further discuss things?", "ko": "알겠습니다. 만나서 더 논의하시겠어요?"}, {"sp": "M", "en": "Yes. Are you available next Tuesday at 1 P.M.? There's a quiet café across the street from my office where we could meet. It's called The Oxford Club.", "ko": "네. 다음 주 화요일 오후 1시에 시간 괜찮으신가요? 저희 사무실 길 건너편에 우리가 만날 수 있는 조용한 카페가 있어요. The Oxford Club이라고 해요."}, {"sp": "W", "en": "Wonderful. See you then.", "ko": "좋아요. 그때 봬요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음 → 호주식 발음", "audio": "Test07_53-55.mp3", "qs": [{"n": 53, "q": "Where most likely is the conversation taking place?", "opts": ["At a repair shop", "At a moving company", "At a showroom", "At a manufacturing plant"], "ans": 3, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 54, "q": "What does the woman mean when she says, \"I've got to go to Mr. Hanson's office now\"?", "opts": ["She is running late for a meeting.", "She cannot assist with a task.", "She did not complete an assignment.", "She will check an order form."], "ans": 1, "ko": "여자는 \"저는 지금 Mr. Hanson의 사무실에 가야 해요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 55, "q": "What is Josh asked to do?", "opts": ["Examine some furniture", "Track a shipment", "Get some equipment", "Contact a customer"], "ans": 2, "ko": "Josh는 무엇을 하도록 요청받는가?"}], "script": [{"sp": "M1", "en": "Can you two help me with something? An order of office furniture is currently in the warehouse on the other side of the factory. But the items need to be moved to the loading dock for shipment to the customer.", "ko": "두 분이 저를 좀 도와주실 수 있나요? 사무용 가구 주문품이 지금 공장의 반대편에 있는 창고에 있어요. 하지만 그 물품들은 고객에게 운송하기 위해 짐을 싣는 부두로 옮겨져야 해요."}, {"sp": "W", "en": "I've got to go to Mr. Hanson's office now. He wants to discuss the new delivery trucks we are planning to purchase.", "ko": "저는 지금 Mr. Hanson의 사무실에 가야 해요. 그는 우리가 구입하고자 하는 새로운 배송 트럭에 대해 논의하기를 원해요."}, {"sp": "M1", "en": "OK. What about you, Josh?", "ko": "알겠어요. 당신은 어때요, Josh?"}, {"sp": "M2", "en": "I'm free now. Let's get started right away.", "ko": "저는 지금 한가해요. 바로 시작하죠."}, {"sp": "M1", "en": "Great. Could you get a couple of handcarts? We'll need them to move the furniture.", "ko": "좋아요. 손수레 몇 개를 갖고 와 주시겠어요? 우리는 가구를 옮기기 위해 그것들이 필요할 거예요."}, {"sp": "M2", "en": "Sure. Let's meet at the warehouse in about 20 minutes.", "ko": "물론이죠. 20분쯤 뒤에 창고에서 만나요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test07_56-58.mp3", "qs": [{"n": 56, "q": "Why is the man calling?", "opts": ["To apply for Internet banking", "To request a new credit card", "To open a bank account", "To report a transaction error"], "ans": 1, "ko": "남자는 왜 전화를 하고 있는가?"}, {"n": 57, "q": "What must the man do?", "opts": ["Update his account information", "Explain a company policy", "Enter an extension number", "Complete a form online"], "ans": 3, "ko": "남자는 무엇을 해야 하는가?"}, {"n": 58, "q": "What does the man want to change?", "opts": ["A billing address", "A spending restriction", "His credit card provider", "His contact information"], "ans": 1, "ko": "남자는 무엇을 변경하고 싶어 하는가?"}], "script": [{"sp": "M", "en": "Hello, my name is Raj Shan. I'm calling because there's an issue with my credit card. Its . . . magnetic strip is worn, and scanners can't read it. So, I need a replacement.", "ko": "안녕하세요, 제 이름은 Raj Shan입니다. 제 신용 카드에 문제가 있어서 전화드렸습니다. 그것의… 마그네틱 띠가 닳아서, 판독 장치가 인식하지 못해요. 그래서 교체 물품이 필요해요."}, {"sp": "W", "en": "Certainly, Mr. Shan. To get one, you must fill out the necessary form on our Web site.", "ko": "물론입니다, Mr. Shan. 교체 물품을 받으시려면, 저희 웹사이트에서 필요한 양식을 작성하셔야 합니다."}, {"sp": "M", "en": "Can't we take care of that over the phone?", "ko": "전화상으로 그것을 처리할 수는 없나요?"}, {"sp": "W", "en": "I'm afraid not. We have a strict procedure for such requests.", "ko": "유감이지만 그렇게는 할 수 없습니다. 저희는 그러한 요청들에 대해 엄격한 절차가 있습니다."}, {"sp": "M", "en": "Oh, I see.", "ko": "아, 알겠습니다."}, {"sp": "W", "en": "Just go to our Web site and then click on the card replacement link. You'll find the necessary instructions there.", "ko": "그저 저희 웹사이트에서 가셔서 카드 교체 링크를 클릭하세요. 거기에서 필요한 설명들을 보실 수 있을 겁니다."}, {"sp": "M", "en": "OK. By the way, can I adjust the card's credit limit on the Web site too?", "ko": "알겠어요. 그런데, 제가 웹사이트에서 카드의 신용 한도도 조정할 수 있나요?"}, {"sp": "W", "en": "Yep, you'll be able to do that as well.", "ko": "네, 그것 또한 하실 수 있을 거예요."}, {"sp": "M", "en": "Great. Thanks for the information.", "ko": "좋아요. 알려주셔서 감사합니다."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 영국식 발음", "audio": "Test07_59-61.mp3", "qs": [{"n": 59, "q": "What is mentioned about Mark Mason?", "opts": ["He misplaced an application.", "He is employed at a factory.", "He recently received a raise.", "He is planning to retire soon."], "ans": 1, "ko": "Mark Mason에 관해 무엇이 언급되는가?"}, {"n": 60, "q": "Why did Mark Mason send an e-mail?", "opts": ["To inform workers about a policy", "To notify a candidate about a change", "To confirm an interview date", "To discuss an opening"], "ans": 3, "ko": "Mark Mason은 왜 이메일을 보냈는가?"}, {"n": 61, "q": "What will probably happen after lunch?", "opts": ["A staff member will be contacted.", "A session will conclude.", "A memo will be distributed.", "A submission will be reviewed."], "ans": 0, "ko": "점심시간 후에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "W1", "en": "Have you filled the vacant manager position at our Chicago factory? I'm curious because the plant's assistant manager, Mark Mason, e-mailed me about the job this morning. He'd like to apply for it.", "ko": "우리 시카고 공장에 공석인 관리자 자리를 채우셨나요? 제가 궁금한 이유는 공장의 보조 관리자인 Mark Mason이 오늘 아침에 제게 그 일자리에 대해 이메일을 보냈기 때문이에요. 그는 그 자리에 지원하고 싶어 해요."}, {"sp": "W2", "en": "I've received a few applications but haven't selected anyone for the position yet. Please tell Mr. Mason that I'd be happy to consider his application. And since he's already an employee at our company, he doesn't need to provide any reference letters.", "ko": "저는 몇몇 지원서들을 받았지만 아직 그 자리에 누구도 선정하지 못했어요. Mr. Mason에게 기꺼이 그의 지원서를 고려해보겠다고 말해주세요. 그리고 그는 이미 우리 회사의 직원이니까, 추천서를 준비할 필요는 없어요."}, {"sp": "W1", "en": "OK, I'll message him after lunch to let him know. He'll most likely send you his résumé within a day or two. Good luck deciding on an applicant.", "ko": "네, 제가 점심시간 후에 그에게 메시지를 보내 알려줄게요. 그는 아마도 하루나 이틀 안에 당신에게 이력서를 보낼 거예요. 지원자를 결정하시는 게 잘 됐으면 좋겠네요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test07_62-64.mp3", "qs": [{"n": 62, "q": "Why is the man going to Madrid?", "opts": ["To take a facility tour", "To attend a business conference", "To negotiate a merger", "To meet with a client"], "ans": 0, "ko": "남자는 왜 마드리드에 가는가?"}, {"n": 63, "q": "Look at the graphic. Who will the man most likely study Spanish with?", "opts": ["Diego Lopez", "Sarah Rodriguez", "Jose Garcia", "Jennifer Alcon"], "ans": 2, "ko": "시각 자료를 보시오. 남자는 누구와 스페인어를 공부할 것 같은가?"}, {"n": 64, "q": "What does the woman ask the man to do?", "opts": ["Provide contact information", "Pay a lesson fee", "Contact an instructor", "Confirm registration"], "ans": 0, "ko": "여자는 남자에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "W", "en": "You've reached the Wilson Language Academy.", "ko": "Wilson 언어 교육원입니다."}, {"sp": "M", "en": "Hello. I'm interested in taking Spanish lessons with a private tutor once a week.", "ko": "안녕하세요. 저는 일주일에 한 번 개인 지도 교사에게 스페인어 수업을 받는 것에 관심이 있어요."}, {"sp": "W", "en": "Have you studied Spanish before?", "ko": "이전에 스페인어를 공부해 보신 적이 있나요?"}, {"sp": "M", "en": "Yes, but I need to improve my business vocabulary. My company merged with a firm in Madrid, and I'll be inspecting its factory next month. I need to be able to communicate with the people showing me around the plant.", "ko": "네, 하지만 저는 비즈니스 어휘를 향상시켜야 해요. 저희 회사가 마드리드에 있는 기업과 합병했고, 저는 다음 달에 공장을 점검하게 될 거예요. 저는 공장 주변을 안내해주는 사람들과 소통할 수 있어야 해요."}, {"sp": "W", "en": "I see . . . Which day do you want to meet with a tutor?", "ko": "그렇군요… 개인 지도 교사와 어느 요일에 만나고 싶으세요?"}, {"sp": "M", "en": "I'm usually busy from Monday to Thursday, so Friday evenings would be best.", "ko": "저는 보통 월요일부터 목요일까지 바빠서, 금요일 저녁이 가장 좋겠어요."}, {"sp": "W", "en": "OK. If you could give me your e-mail address, I'll send you some details about the available tutor and the cost of the lessons.", "ko": "알겠습니다. 당신의 이메일 주소를 제게 주신다면, 제가 가능한 개인 지도 교사와 수업료에 대한 세부 사항들을 보내드릴게요."}], "gimg": "hk2_t7_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test07_65-67.mp3", "qs": [{"n": 65, "q": "What did the man recently do?", "opts": ["Became a company spokesperson", "Created a mobile phone application", "Presented a promotional idea", "Assigned a task"], "ans": 2, "ko": "남자는 최근에 무엇을 했는가?"}, {"n": 66, "q": "What problem is mentioned?", "opts": ["An advertisement is too long.", "Some instructions lack clarity.", "A launch event cannot be postponed.", "A message is overly complicated."], "ans": 3, "ko": "어떤 문제가 언급되는가?"}, {"n": 67, "q": "Look at the graphic. When was a previous campaign released?", "opts": ["In February", "In March", "In April", "In May"], "ans": 2, "ko": "시각 자료를 보시오. 이전의 캠페인은 언제 공개되었는가?"}], "script": [{"sp": "M", "en": "I finally had a chance to meet with the president and tell her about our new advertising idea for smartphone applications.", "ko": "제가 드디어 회장님을 만나서 스마트폰 애플리케이션에 대한 우리의 새로운 광고 계획을 말씀드릴 기회가 있었어요."}, {"sp": "W", "en": "And? How did it go?", "ko": "그래서요? 어떻게 되었나요?"}, {"sp": "M", "en": "Not as expected. She feels that the message of the advertisement is too complex. She wants us to make it more straightforward and easy to understand.", "ko": "기대한 대로는 아니에요. 그녀는 광고의 메시지가 너무 복잡하다고 생각해요. 그녀는 우리가 그것을 더 간단하고 이해하기 쉽게 만들기를 원해요."}, {"sp": "W", "en": "That seems reasonable. Well, maybe we can make it more like the one from the campaign we launched earlier this year. You know—the previous advertisement that was released in the month in which we had more than 11,000 views for the first time this year.", "ko": "타당한 것 같네요. 음, 아마도 우리가 그것을 올해 초에 내놓은 캠페인에 더 가깝게 만들 수 있을 거예요. 있잖아요, 올해 처음으로 11,000번 이상의 열람이 있었던 달에 공개된 이전 광고요."}], "gimg": "hk2_t7_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test07_68-70.mp3", "qs": [{"n": 68, "q": "Who is Myra Lawrence?", "opts": ["A university instructor", "A professional gardener", "A Web site designer", "A facility manager"], "ans": 0, "ko": "Myra Lawrence는 누구인가?"}, {"n": 69, "q": "Look at the graphic. When will the man probably visit the botanical garden?", "opts": ["On July 2", "On July 4", "On July 6", "On July 7"], "ans": 3, "ko": "시각 자료를 보시오. 남자는 언제 식물원을 방문할 것 같은가?"}, {"n": 70, "q": "What is the man instructed to do?", "opts": ["Purchase materials in advance", "Change an appointment time", "Select an online link", "E-mail a registration form"], "ans": 2, "ko": "남자는 무엇을 하도록 안내되는가?"}], "script": [{"sp": "M", "en": "Hello. I'm calling because I heard you're holding special events at your botanical garden in July. Is that correct?", "ko": "안녕하세요. 7월에 귀하의 식물원에서 특별 행사들을 연다고 들어서 전화드렸습니다. 그것이 맞나요?"}, {"sp": "W", "en": "Yes. The tour of the facility is especially popular. It's conducted by Myra Lawrence . . . um, an assistant botany professor from a local university.", "ko": "네. 시설 투어가 특히 인기가 있습니다. 그것은 Myra Lawrence에 의해 안내돼요… 음, 지역 대학의 식물학과 조교수요."}, {"sp": "M", "en": "Actually, I'd like to take one of the classes. However, given my work hours, I'll only be able to attend one on the weekend.", "ko": "실은, 저는 수업들 중 하나를 듣고 싶어요. 그런데, 제 근무 시간을 고려해 봤을 때, 저는 주말에 있는 수업에만 참석할 수 있을 거예요."}, {"sp": "W", "en": "Certainly. But you'll need to sign up ahead of time on our Web site. Simply click on the day you'd like to attend, and you'll be directed to the registration page.", "ko": "물론입니다. 하지만 미리 저희 웹사이트에서 등록을 하셔야 할 겁니다. 귀하께서 참석하기를 원하시는 요일을 클릭만 하시면, 등록 페이지로 안내되실 것입니다."}], "gimg": "hk2_t7_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test07_71-73.mp3", "qs": [{"n": 71, "q": "What facility does the teahouse include?", "opts": ["A parking lot", "A stage for performances", "A private library", "An area for sleeping"], "ans": 3, "ko": "찻집은 어떤 시설을 포함하는가?"}, {"n": 72, "q": "What is mentioned about the teahouse?", "opts": ["It overlooks the entire city.", "It hosted many notable events.", "It has innovative architectural features.", "It was owned by the royal family."], "ans": 1, "ko": "찻집에 관해 무엇이 언급되는가?"}, {"n": 73, "q": "According to the speaker, what is the teahouse now used as?", "opts": ["A venue for government ceremonies", "A destination for visiting tourists", "A location for live shows", "A facility for storing historic artifacts"], "ans": 1, "ko": "화자에 따르면, 찻집은 이제 무엇으로 사용되는가?"}], "script": [{"sp": "M", "en": "Welcome to the Masami Teahouse in Kyoto, Japan. The teahouse was built in the late 1700s and originally served as a private club for prestigious members of society. As you can see on this map, the complex includes a large dining area, kitchen, ceremonial rooms, garden, and even sleeping quarters for guests. Moreover, the teahouse was also used for numerous special occasions, including weddings, political gatherings, and receptions for members of the royal family. It now functions as a popular tourist site.", "ko": "일본 교토의 Masami 찻집에 오신 것을 환영합니다. 이 찻집은 1700년대 말에 지어졌으며 원래는 사회의 상류 계층 회원들을 위한 비공개 클럽으로 사용되었습니다. 이 지도에서 볼 수 있듯이, 이 복합 건물은 넓은 식사 공간, 주방, 식장, 정원, 그리고 심지어 방문객을 위한 숙소도 포함하고 있습니다. 게다가, 이 찻집은 결혼식, 정치적인 모임, 그리고 왕실 구성원들을 위한 연회를 포함한 다양한 특별 행사들을 위해서도 사용되었습니다. 이곳은 이제 인기 있는 관광지로서 역할을 하고 있습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test07_74-76.mp3", "qs": [{"n": 74, "q": "What kind of business is being advertised?", "opts": ["A gardening company", "A flower shop", "A banquet hall", "An interior design firm"], "ans": 1, "ko": "어떤 종류의 업체가 광고되고 있는가?"}, {"n": 75, "q": "According to the speaker, why should listeners visit Green Solutions?", "opts": ["To browse through merchandise", "To make a booking", "To place a customized order", "To get an initial estimate"], "ans": 0, "ko": "화자에 따르면, 청자들은 왜 Green Solutions를 방문해야 하는가?"}, {"n": 76, "q": "How can listeners receive a price reduction?", "opts": ["By printing out a coupon", "By placing a phone call", "By mentioning a commercial", "By making a minimum purchase"], "ans": 2, "ko": "청자들은 어떻게 가격 할인을 받을 수 있는가?"}], "script": [{"sp": "M", "en": "Whether you are decorating a reception hall or looking for a simple gift, Green Solutions has the perfect floral arrangement for you! That's because we are one of Edinburgh's largest floral shops. In fact, we have over 3,000 square meters of showroom space full of beautiful plants and vases. To view our huge selection of premade arrangements, come to our store at 341 Vincent Street. Customers who mention this advertisement to one of our cashiers will qualify for a 5 percent discount on any purchase.", "ko": "여러분이 피로연장을 장식하고 있든지 아니면 간단한 선물을 찾고 있든지, Green Solutions에는 여러분을 위한 완벽한 꽃 장식이 있습니다! 그것은 저희가 에든버러의 가장 큰 꽃 가게들 중 하나이기 때문입니다. 실제로, 저희는 아름다운 식물과 꽃병들로 가득한 3천 제곱미터 이상의 전시실 공간이 있습니다. 저희의 이미 만들어져 있는 많은 종류의 장식들을 보시려면, Vincent가 341번지에 있는 저희 가게로 오세요. 저희 계산원들 중 한 명에게 이 광고를 언급하시는 고객분들은 모든 구매에 대해 5퍼센트 할인 자격을 얻으실 것입니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test07_77-79.mp3", "qs": [{"n": 77, "q": "What did the speaker do last Tuesday?", "opts": ["Participated in a meeting", "Stopped by a flea market", "Left a voice mail", "Turned down an offer"], "ans": 0, "ko": "화자는 지난 화요일에 무엇을 했는가?"}, {"n": 78, "q": "What does the speaker mean when he says, \"having a painter around would attract a new set of shoppers\"?", "opts": ["The listener should contact an artist.", "The listener has been selected for a spot.", "Some customer requests have been implemented.", "Some paintings sold better than expected."], "ans": 1, "ko": "화자는 \"화가를 유치하는 것이 새로운 무리의 쇼핑객들을 끌어모을 것\"이라고 말할 때 무엇을 의도하는가?"}, {"n": 79, "q": "What does the speaker encourage the listener to do?", "opts": ["Come to an office", "Submit an application", "Sign up for a time slot", "Return a contract"], "ans": 0, "ko": "화자는 청자에게 무엇을 하라고 권하는가?"}], "script": [{"sp": "M", "en": "Hello. This is Eric Krauss from Timberlake Flea Market. I'm calling for Theresa McCartney, who I met with last Tuesday. We received over 50 applications for the vendor stall that will soon be available, so it wasn't easy to decide who to pick. However, I really liked your paintings, and I think having a painter around would attract a new set of shoppers. Now, the booth that was advertised is currently occupied, but it will be vacant in three weeks. In the meantime, we need to get your signature on the rental agreement. I'll be in the office from 8 A.M. to 6 P.M. tomorrow, so stop by anytime.", "ko": "안녕하세요. 저는 Timberlake 벼룩시장의 Eric Krauss입니다. 저는 지난 화요일에 만난 Theresa McCartney에게 전화드립니다. 저희는 곧 이용 가능하게 될 노점상에 대해 50개가 넘는 신청서를 받아서, 누구를 뽑을지 결정하기가 쉽지 않았습니다. 하지만 저는 당신의 그림이 매우 좋았고, 화가를 유치하는 것이 새로운 무리의 쇼핑객들을 끌어모을 것이라고 생각합니다. 음, 광고가 되었던 그 노점은 현재 사용되고 있습니다만, 3주 후에는 비게 될 것입니다. 그동안에, 저희는 임대 계약서에 당신의 서명을 받아야 합니다. 저는 내일 오전 8시부터 오후 6시까지 사무실에 있을 것이니, 언제든지 들러 주십시오."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test07_80-82.mp3", "qs": [{"n": 80, "q": "What does the speaker mention about the commuter train system?", "opts": ["It failed a government inspection.", "It had to be completely shut down.", "It is disliked by some individuals.", "It recently underwent repairs."], "ans": 2, "ko": "화자는 통근 전철에 관해 무엇을 언급하는가?"}, {"n": 81, "q": "What did Mary Stenos do on Wednesday?", "opts": ["Met with media representatives", "Stopped by a construction site", "Announced new regulations", "Launched an online forum"], "ans": 0, "ko": "Mary Stenos는 수요일에 무엇을 했는가?"}, {"n": 82, "q": "According to the speaker, why should listeners visit the Web site?", "opts": ["To download some brochures", "To check the status of a project", "To submit questions about a plan", "To view a schedule for a conference"], "ans": 1, "ko": "화자에 따르면, 청자들은 왜 웹사이트에 방문해야 하는가?"}], "script": [{"sp": "W", "en": "In other news, transportation officials in Austin have temporarily halted construction of the SwiftRail commuter train system. The interruption comes amid criticism from a group of local citizens. Residents from the Kingfield neighborhood are claiming that rail lines are being built too close to their homes. Mary Stenos, the head of the transportation department, held a press conference on Wednesday regarding the matter. She stated that residents' complaints were being taken seriously and that work on the SwiftRail would be stopped until the issue is resolved. She also said that updates will continue to be posted at www.swiftrail.gov to keep the public informed on the progress of construction.", "ko": "다른 뉴스로, 오스틴의 교통 공무원들이 SwiftRail 통근 전철의 공사를 일시적으로 중단했습니다. 이 중단은 지역 시민들의 비판 속에 일어났습니다. Kingfield 인근의 주민들은 철로가 그들의 집에 너무 가까이 지어지고 있다고 주장하고 있습니다. 교통부 장관인 Mary Stenos는 수요일에 이 문제에 관한 기자 회견을 열었습니다. 그녀는 주민들의 항의가 심각하게 받아들여지고 있으며 이 문제가 해결될 때까지 SwiftRail의 해당 작업이 중단될 것이라고 표명했습니다. 그녀는 또한 대중들이 공사의 진행 상황을 꾸준히 알 수 있도록 www.swiftrail.gov에 최신 정보가 계속해서 게시될 것이라고 말했습니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test07_83-85.mp3", "qs": [{"n": 83, "q": "What is being advertised?", "opts": ["A staffing company", "A talent agency", "A legal firm", "A consulting service"], "ans": 0, "ko": "무엇이 광고되고 있는가?"}, {"n": 84, "q": "What service does Ace Solutions provide?", "opts": ["Camera installation", "Certification courses", "Background checks", "On-site training"], "ans": 2, "ko": "Ace Solutions는 어떤 서비스를 제공하는가?"}, {"n": 85, "q": "What does the speaker recommend that the listeners do?", "opts": ["Provide feedback on a service", "Sign up for a newsletter", "Renew a membership", "Take advantage of an offer"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 제안하는가?"}], "script": [{"sp": "M", "en": "If you are looking to hire trained security personnel to protect your home or business, contact Ace Solutions today. We can provide access to over 10,000 trained guards throughout the country who are available for employment on a permanent or short-term basis. All of the individuals we represent undergo a rigorous screening process to confirm their work experience, educational history, and professional certification. This means that you do not have to worry about searching for qualified applicants. In addition, if you sign up for a membership before April 2, you will receive 50 percent off your first month of service. Don't miss out on this great opportunity! Please feel free to call our customer service hotline for more information.", "ko": "만약 귀하의 집이나 회사를 보호하기 위해 숙련된 보안 직원을 고용하려고 하신다면, 오늘 Ace Solutions에 연락하세요. 저희는 정규직이나 단기 직무로 고용할 수 있는 10,000명이 넘는 숙련된 경비원들에 대한 접근권을 전국적으로 제공할 수 있습니다. 저희가 대표하는 모든 사람들은 그들의 경력, 학력, 그리고 전문 자격증을 확인하기 위한 엄격한 심사 절차를 거칩니다. 이는 당신이 자격이 있는 후보자들을 찾는 것에 대해 걱정하지 않아도 됨을 의미합니다. 게다가, 4월 2일 이전에 회원으로 등록하시면, 첫 달 서비스의 50퍼센트를 할인받으실 것입니다. 이 좋은 기회를 놓치지 마세요! 더 많은 정보를 원하시면, 언제든지 저희 고객 서비스 상담 전화로 전화해주세요."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test07_86-88.mp3", "qs": [{"n": 86, "q": "Where most likely are the listeners?", "opts": ["At a writing seminar", "At a literary reading", "At an awards ceremony", "At a fiction convention"], "ans": 1, "ko": "청자들은 어디에 있는 것 같은가?"}, {"n": 87, "q": "What is the speaker's newest work about?", "opts": ["Her favorite author", "The history of South Africa", "Her personal experiences", "The psychology of children"], "ans": 2, "ko": "화자의 최신 작품은 무엇에 관한 것인가?"}, {"n": 88, "q": "Why does the speaker say, \"Copies have been placed in the back of the room\"?", "opts": ["To make a correction", "To ask for assistance", "To encourage purchases", "To initiate an exercise"], "ans": 2, "ko": "화자는 왜 \"책들은 이 방의 뒤편에 놓여 있습니다\"라고 말하는가?"}], "script": [{"sp": "W", "en": "I'd like to thank Littleton Books for inviting me here this evening. And I'm also grateful to everyone in the audience for showing up. Today, I'll be sharing several excerpts from my latest book, Tiger in the Night. This work is an autobiography based on my experiences in a South African town, including my troubled teenage years and my struggles in becoming a published writer. If you like what you hear, the book is currently 10 percent off. Copies have been placed in the back of the room.", "ko": "오늘 저녁 여기에 저를 초대해 주신 것에 대해 Littleton Books에 감사드리고 싶습니다. 그리고 저는 또한 모든 청중분들께서 와주신 것에 대해 감사드립니다. 오늘, 저는 저의 최신 도서인 Tiger in the Night에서 몇몇 발췌 부분을 공유할 것입니다. 이 작품은 힘들었던 제 십 대 시절과 출판 작가가 되어가는 저의 분투를 포함하여, 남아프리카공화국 마을에서의 제 경험들을 토대로 하는 자서전입니다. 여러분께서 들으시는 것이 좋으시다면, 이 책은 현재 10퍼센트 할인되고 있습니다. 책들은 이 방의 뒤편에 놓여 있습니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test07_89-91.mp3", "qs": [{"n": 89, "q": "Where are the listeners?", "opts": ["At a shareholder meeting", "At a convention", "At an orientation", "At a manufacturing plant tour"], "ans": 1, "ko": "청자들은 어디에 있는가?"}, {"n": 90, "q": "What do some companies contract Lifan to do?", "opts": ["Conduct quality control testing", "Promote their products", "Ship goods internationally", "Manufacture components"], "ans": 3, "ko": "몇몇 회사들은 Lifan사가 무엇을 하도록 계약하는가?"}, {"n": 91, "q": "What most likely will happen next?", "opts": ["A customer survey will be discussed.", "A speaker will take the stage.", "New products will be revealed.", "Additional handouts will be distributed."], "ans": 2, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "I am honored to be here on behalf of Lifan Industries at this year's Consumer Electronics Show. Lifan Industries was founded over 25 years ago as a supplier of plastic parts to television manufacturers. Over time, however, we have produced increasingly high-tech products. Today, Lifan has exclusive contracts to produce LED screens and chipsets for major corporations such as Silverstar, Vivica, and PTF. What's more, I'm pleased to announce that Lifan Industries will begin producing consumer electronics under its own brand next year. If you'll all turn your attention to the screen here, I'll give you a glimpse of some of the products that we plan to launch in January.", "ko": "저는 올해의 가전제품 전시회에서 Lifan사를 대표하여 이곳에 있게 되어 영광입니다. Lifan사는 25년도 더 전에 텔레비전 제조 업체의 플라스틱 부품 공급 업체로 설립되었습니다. 그러나, 시간이 지나면서 저희는 점점 더 첨단 기술의 부품들을 제조해왔습니다. 오늘날, Lifan사는 Silverstar, Vivica, 그리고 PTF와 같은 주요 기업들을 위해 LED 화면과 칩셋을 제조하는 독점 계약을 맺고 있습니다. 더욱이, 저는 Lifan사가 내년에 자사의 브랜드로 가전제품을 제조하기 시작할 것임을 발표하게 되어 기쁩니다. 여기 화면에 모두 주목해주시면, 1월에 출시할 예정인 제품의 일부를 잠깐 보여드리겠습니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test07_92-94.mp3", "qs": [{"n": 92, "q": "Why is an agent unable to be reached?", "opts": ["She is taking personal leave.", "She is at a film festival.", "She has turned her mobile phone off.", "She has to meet with a client."], "ans": 0, "ko": "대리인은 왜 연락이 되지 않는가?"}, {"n": 93, "q": "What does the speaker mean when she says, \"Most of your parts have been in action movies\"?", "opts": ["A director has voiced some concerns.", "A screenplay can still be revised.", "A role matches a performer's experience.", "A proposal might seem unfitting."], "ans": 3, "ko": "화자는 \"당신 역할들의 대부분은 액션 영화에서였죠\"라고 말할 때 무엇을 의도하는가?"}, {"n": 94, "q": "What will the speaker provide to the listener?", "opts": ["An audition schedule", "A draft of a script", "Some legal documents", "Some contact information"], "ans": 1, "ko": "화자는 청자에게 무엇을 제공할 것인가?"}], "script": [{"sp": "W", "en": "Good morning, Mr. Parker. This is Akita Kang from Goldman and Associates. I'm interested in having you audition for a movie that my agency has been hired to do the casting for. I was going to speak to your agent about this, but she is apparently on vacation until next month. So, I decided to contact you directly. Anyway, it is a supporting role in a romantic comedy. I know . . . Most of your parts have been in action movies. But it's a great opportunity to expand your résumé and try something new. You have several days to make a decision. I'll send you a preliminary copy of the screenplay to look over. Let me know what you think.", "ko": "안녕하세요, Mr. Parker. 저는 Goldman and Associates사의 Akita Kang입니다. 저는 저희 기획사에서 캐스팅을 하게 된 영화에 당신이 오디션을 보도록 하는 것에 관심이 있습니다. 이에 대해 당신의 대리인에게 이야기하고자 했으나, 듣자 하니 그녀는 다음 달까지 휴가 중인 것 같습니다. 그래서, 제가 당신에게 직접 연락하기로 결정했습니다. 아무튼, 이것은 로맨틱 코미디의 조연입니다. 알아요... 당신 역할들의 대부분은 액션 영화에서였죠. 하지만 이것은 당신의 이력을 넓히고 새로운 것에 도전할 아주 좋은 기회입니다. 당신에게는 결정할 시간이 며칠 있습니다. 당신이 살펴볼 수 있도록 영화의 임시 대본 한 부를 보내드리겠습니다. 어떻게 생각하는지 알려주세요."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "호주식 발음", "audio": "Test07_95-97.mp3", "qs": [{"n": 95, "q": "Who most likely is the speaker addressing?", "opts": ["Students", "Jobseekers", "College administrators", "Business representatives"], "ans": 3, "ko": "화자는 누구에게 말하고 있는 것 같은가?"}, {"n": 96, "q": "What is mentioned about Global Education?", "opts": ["It has had difficulty finding employees recently.", "It has offices around the world.", "It has reserved the largest booth.", "It has not participated in the event before."], "ans": 3, "ko": "Global Education사에 관해 무엇이 언급되는가?"}, {"n": 97, "q": "Look at the graphic. Where will engineering staff be located?", "opts": ["In Hall A", "In Hall B", "In Hall C", "In Hall D"], "ans": 0, "ko": "시각 자료를 보시오. 엔지니어링 직원들은 어디에 있을 것인가?"}], "script": [{"sp": "M", "en": "Thank you all so much for joining our annual job fair. Your participation will be especially appreciated by our students. Many of them have experienced problems finding companies interested in hiring recent college graduates during this recession. We're happy to welcome many new corporate partners this year, including our sponsor, Global Education. Just one quick note. There has been a switch in the room assignments. We originally planned to have representatives from engineering companies in Hall B, but more of these types of firms sent workers than expected, so we've decided to let them use the larger space next door. OK, feel free to set up your display booths. You have an hour before people start arriving.", "ko": "여러분 모두 저희 연례 취업 박람회에 참여해 주셔서 대단히 감사합니다. 여러분의 참여는 특히 저희 학생들에게 감사하게 여겨질 것입니다. 많은 학생들이 이 불경기 동안 최근에 졸업한 대학생들을 고용하고자 하는 회사를 찾는 데 어려움을 겪어왔습니다. 저희의 후원사인 Global Education사를 포함한 많은 새로운 제휴 업체들을 맞이하게 되어 기쁩니다. 간단히 하나만 말씀드리겠습니다. 장소 배정에 변경이 있었습니다. 저희는 원래 엔지니어링 회사의 대표들이 B홀을 사용하도록 계획했었지만, 이 종류의 회사들이 예상보다 더 많이 직원들을 보냈기 때문에, 그들이 옆의 더 큰 장소를 사용하도록 결정했습니다. 좋습니다, 여러분의 전시 부스를 자유롭게 설치하십시오. 사람들이 도착하기 전까지 한 시간이 남았습니다."}], "gimg": "hk2_t7_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test07_98-100.mp3", "qs": [{"n": 98, "q": "What did the speaker fail to do?", "opts": ["Book a room in advance", "Review some details", "Request a copy of a statement", "Report an error to a supervisor"], "ans": 1, "ko": "화자는 무엇을 하지 못했는가?"}, {"n": 99, "q": "Look at the graphic. How much will the speaker probably be refunded?", "opts": ["$138.99", "$8.98", "$15.79", "$46.00"], "ans": 2, "ko": "시각 자료를 보시오. 화자는 얼마를 환불받을 것 같은가?"}, {"n": 100, "q": "What will the speaker most likely do on Friday?", "opts": ["Submit a document", "Leave for a trip", "Contact a hotel", "Respond to an e-mail"], "ans": 0, "ko": "화자는 금요일에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Good afternoon. This is Beverly Gilder. I stayed at the . . . um . . . Presidential Palace for the first time when I was in Manila last week. While I enjoyed the experience, I've run into a problem. I didn't closely examine my bill upon check-out, and I just noticed an error. I was charged for laundry services that I did not use. I would like you to review your billing records, refund me the amount in question, and e-mail me a corrected bill. This needs to be done as soon as possible because I have to turn in my final expense report on Friday. Thank you.", "ko": "안녕하세요. 저는 Beverly Gilder입니다. 지난주에 마닐라에 있었을 때… 음… Presidential Palace에 처음으로 묵었습니다. 즐거운 경험이었지만, 문제가 하나 생겼습니다. 퇴실할 때 청구서를 유심히 검토하지 않았었는데, 잘못된 것이 있음을 방금 알았습니다. 제가 사용하지 않은 세탁 서비스에 대한 요금이 청구되었습니다. 청구 명세를 확인하셔서, 문제의 금액을 환불해 주시고, 정정된 청구서를 이메일로 발송해 주시기를 바랍니다. 금요일에 최종 경비 보고서를 제출해야 하기 때문에 이는 가능한 한 빨리 처리되어야 합니다. 감사합니다."}], "gimg": "hk2_t7_g98.jpg"}]};
